#include <bits/stdc++.h>

class Solution {
public:
    int totalFruit(const std::vector<int>& fruits) {
        int n = fruits.size();
        int max_trees = 0;
        int l = 0, r = 0;
        
        //for (int i = 0; i < n; i++) {
        //    std::unordered_map<char, int> map;
        //    for (int j = i; j < n; j++) {
        //        map[fruits[j]]++;
        //        if (map.size() > 2) break;
        //        max_trees = std::max(max_trees, j - i + 1);
        //    }
        //}        

        std::unordered_map<int, int> map;
        while (r < n) {
            map[fruits[r]]++;
            while (map.size() > 2) {
                map[fruits[l]]--; 
                if (map[fruits[l]] == 0)
                    map.erase(fruits[l]);
                l++;
            }
            max_trees = std::max(max_trees, r - l + 1);
            r++;
        }

        return max_trees;
    }
};

